const candidates = $('Fetch Upsell Candidates').first().json;
const accuracy = $('Fetch 7-Day Accuracy').first().json;

const users = Array.isArray(candidates) ? candidates : (candidates.users || []);

if (users.length === 0) {
  return [{ json: { skip: true, message: 'No upsell candidates this week' } }];
}

return users.map(user => ({
  json: {
    skip: false,
    userId: user.telegram_id || user.chat_id || user.id,
    username: user.username || user.first_name || 'there',
    currentPlan: user.plan || user.subscription_type || 'monthly',
    monthsActive: user.months_active || user.tenure_months || 1,
    totalPredictions: user.total_predictions || user.prediction_count || 0,
    accuracy: JSON.stringify(accuracy)
  }
}));

const response = $input.first().json;
let text = '';

if (response.content && response.content.length > 0) {
  text = response.content[0].text;
} else {
  text = '<b>Save 25% with Yearly Premium</b>\n\nYou\'ve been getting great value from BTC Seer. Switch to yearly and save! Tap /premium to see options.';
}

return [{ json: { text, userId: $('Build Claude Prompt').first().json.userId } }];

const result = $input.first().json;
const userId = $('Extract Message Text').first().json.userId;
const success = result.ok === true;

console.log(`[Upsell Yearly] Sent to user ${userId}: ${success ? 'OK' : 'FAILED'}`);

return [{ json: { userId, success, timestamp: new Date().toISOString() } }];
